mapper.select:
SELECT id, business_type, verification_key, code_value, target, expires_at, consumed, created_at, updated_at
FROM shared_verification_codes
WHERE business_type = #{businessType}
  AND verification_key = #{verificationKey}
LIMIT 1

mapper.update:
UPDATE shared_verification_codes
SET consumed = 1,
    updated_at = CURRENT_TIMESTAMP
WHERE business_type = #{businessType}
  AND verification_key = #{verificationKey}
